func solve(nums []int64) []int64 {
	n := len(nums)
	ans := make([]int64, 2*n)

	// First n elements are the same as nums
	for i := 0; i < n; i++ {
		ans[i] = nums[i]
	}

	// Last n elements are the reverse of nums
	for i := 0; i < n; i++ {
		// ans[i + n] = nums[n - i - 1]
		ans[i+n] = nums[n-1-i]
	}

	return ans
}
