func solve(nums []int64) []int64 {
	n := len(nums)
	ans := make([]int64, 2*n)

	// Copy the first n elements (ans[0] to ans[n-1] = nums[0] to nums[n-1])
	for i := 0; i < n; i++ {
		ans[i] = nums[i]
	}

	// Fill the last n elements with the reverse of nums (ans[n] to ans[2n-1] = nums[n-1] down to nums[0])
	for i := 0; i < n; i++ {
		// ans[i + n] corresponds to nums[n - 1 - i]
		ans[i+n] = nums[n-1-i]
	}

	return ans
}
